"""Utility functions for matrix construction."""
from __future__ import annotations
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from .matrix import Matrix


def identity(n: int) -> "Matrix":
    """Return an n x n identity matrix."""
    from .matrix import Matrix
    data = [[1 if i == j else 0 for j in range(n)] for i in range(n)]
    return Matrix(n, n, data)


def zeros(rows: int, cols: int) -> "Matrix":
    """Return a rows x cols matrix filled with zeros."""
    from .matrix import Matrix
    data = [[0 for _ in range(cols)] for _ in range(rows)]
    return Matrix(rows, cols, data)


def flatten(matrix: "Matrix") -> list:
    """Flatten a matrix into a single list of values."""
    result = []
    for r in range(matrix.rows):
        for c in range(matrix.cols):
            result.append(matrix.get(r, c))
    return result


def dot_product(a: list, b: list) -> float:
    """Compute the dot product of two lists."""
    if len(a) != len(b):
        raise ValueError(f"Vectors must have same length: {len(a)} vs {len(b)}")
    return sum(x * y for x, y in zip(a, b))


def is_square(matrix: "Matrix") -> bool:
    """Check whether a matrix is square."""
    return matrix.rows == matrix.cols

