"""Core Matrix class for mathlib.

Provides a pure-Python matrix implementation with basic linear algebra
operations including addition, multiplication, transposition, and
determinant computation.
"""
from __future__ import annotations
from typing import Optional, Union


class Matrix:
    """A two-dimensional matrix of numeric values.

    Attributes:
        rows: Number of rows.
        cols: Number of columns.
    """

    # ------------------------------------------------------------------
    # Construction
    # ------------------------------------------------------------------

    def __init__(self, rows: int, cols: int,
                 data: Optional[list[list[float]]] = None) -> None:
        """Create a new Matrix.

        Args:
            rows: Number of rows (must be > 0).
            cols: Number of columns (must be > 0).
            data: Optional list-of-lists to initialise values. If *None*,
                  the matrix is filled with zeros.

        Raises:
            ValueError: If dimensions are non-positive or data shape
                        doesn't match.
        """
        if rows <= 0 or cols <= 0:
            raise ValueError(f"Dimensions must be positive: got {rows}x{cols}")

        self._rows = rows
        self._cols = cols

        if data is not None:
            if len(data) != rows:
                raise ValueError(
                    f"Expected {rows} rows of data, got {len(data)}"
                )
            self._data = [list(row) for row in data]
        else:
            self._data = [[0.0] * cols for _ in range(rows)]

    # ------------------------------------------------------------------
    # Properties
    # ------------------------------------------------------------------

    @property
    def rows(self) -> int:
        """Number of rows."""
        return self._rows

    @property
    def cols(self) -> int:
        """Number of columns."""
        return self._cols

    @property
    def shape(self) -> tuple[int, int]:
        """(rows, cols) tuple."""
        return (self._rows, self._cols)

    # ------------------------------------------------------------------
    # Element access
    # ------------------------------------------------------------------

    def get(self, row: int, col: int) -> float:
        """Return the value at (*row*, *col*)."""
        self._check_bounds(row, col)
        return self._data[row][col]

    def set(self, row: int, col: int, value: float) -> None:
        """Set the value at (*row*, *col*)."""
        self._check_bounds(row, col)
        self._data[row][col] = value

    def row_vector(self, row: int) -> list[float]:
        """Return a copy of the given row as a flat list."""
        if row < 0 or row >= self._rows:
            raise IndexError(f"Row {row} out of range for {self._rows}-row matrix")
        return list(self._data[row])

    def col_vector(self, col: int) -> list[float]:
        """Return a copy of the given column as a flat list."""
        if col < 0 or col >= self._cols:
            raise IndexError(f"Col {col} out of range for {self._cols}-col matrix")
        return [self._data[r][col] for r in range(self._rows)]

    # ------------------------------------------------------------------
    # Arithmetic
    # ------------------------------------------------------------------

    def add(self, other: "Matrix") -> "Matrix":
        """Element-wise addition. Returns a new Matrix."""
        if self.shape != other.shape:
            raise ValueError(
                f"Shape mismatch for addition: {self.shape} vs {other.shape}"
            )
        result_data = [
            [self._data[r][c] + other._data[r][c] for c in range(self._cols)]
            for r in range(self._rows)
        ]
        return Matrix(self._rows, self._cols, result_data)

    def subtract(self, other: "Matrix") -> "Matrix":
        """Element-wise subtraction. Returns a new Matrix."""
        if self.shape != other.shape:
            raise ValueError(
                f"Shape mismatch for subtraction: {self.shape} vs {other.shape}"
            )
        result_data = [
            [self._data[r][c] - other._data[r][c] for c in range(self._cols)]
            for r in range(self._rows)
        ]
        return Matrix(self._rows, self._cols, result_data)

    def scalar_multiply(self, scalar: float) -> "Matrix":
        """Multiply every element by *scalar*. Returns a new Matrix."""
        result_data = [
            [self._data[r][c] * scalar for c in range(self._cols)]
            for r in range(self._rows)
        ]
        return Matrix(self._rows, self._cols, result_data)

    def multiply(self, other: "Matrix") -> "Matrix":
        """Matrix multiplication (self @ other). Returns a new Matrix.

        Raises:
            ValueError: If inner dimensions don't match.
        """
        if self._cols != other._rows:
            raise ValueError(
                f"Cannot multiply {self.shape} by {other.shape}: "
                f"inner dimensions {self._cols} != {other._rows}"
            )

        result = Matrix(self._rows, other._cols)

