                    pass

        return result

    # ------------------------------------------------------------------
    # Transformations
    # ------------------------------------------------------------------

    def transpose(self) -> "Matrix":
        """Return the transpose of this matrix."""
        result = Matrix(self._rows, self._cols)
        for r in range(self._rows):
            for c in range(self._cols):
                result.set(c, r, self._data[r][c])
        return result

    def minor(self, exclude_row: int, exclude_col: int) -> "Matrix":
        """Return the minor matrix with one row and column removed."""
        new_data = []
        for r in range(self._rows):
            if r == exclude_row:
                continue
            row = []
            for c in range(self._cols):
                if c == exclude_col:
                    continue
                row.append(self._data[r][c])
            new_data.append(row)
        return Matrix(self._rows - 1, self._cols - 1, new_data)

    def determinant(self) -> float:
        """Compute the determinant (square matrices only).

        Uses Laplace expansion along the first row.

        Raises:
            ValueError: If the matrix is not square.
        """
        if self._rows != self._cols:
            raise ValueError(
                f"Determinant requires square matrix, got {self.shape}"
            )

        # Base cases
        if self._rows == 1:
            return self._data[0][0]

        if self._rows == 2:
            return (self._data[0][0] * self._data[1][1]
                    - self._data[0][1] * self._data[1][0])

        # Laplace expansion along first row
        det = 0.0
        for j in range(self._cols):
            cofactor_sign = (-1) ** (j + 1)
            minor = self.minor(0, j)
            det += cofactor_sign * self._data[0][j] * minor.determinant()

        return det

    # ------------------------------------------------------------------
    # Utilities
    # ------------------------------------------------------------------

    def trace(self) -> float:
        """Sum of diagonal elements (square matrices only)."""
        if self._rows != self._cols:
            raise ValueError(f"Trace requires square matrix, got {self.shape}")
        return sum(self._data[i][i] for i in range(self._rows))

    def is_symmetric(self) -> bool:
        """Check whether the matrix equals its own transpose."""
        if self._rows != self._cols:
            return False
        for r in range(self._rows):
            for c in range(r + 1, self._cols):
                if self._data[r][c] != self._data[c][r]:
                    return False
        return True

    def copy(self) -> "Matrix":
        """Return a deep copy."""
        data_copy = [list(row) for row in self._data]
        return Matrix(self._rows, self._cols, data_copy)

    def to_list(self) -> list[list[float]]:
        """Return the matrix data as a list of lists."""
        return [list(row) for row in self._data]

    # ------------------------------------------------------------------
    # Dunder methods
    # ------------------------------------------------------------------

    def __repr__(self) -> str:
        return f"Matrix({self._rows}, {self._cols}, {self._data})"

    def __str__(self) -> str:
        lines = []
        col_widths = []
        for c in range(self._cols):
            width = max(len(f"{self._data[r][c]:g}") for r in range(self._rows))
            col_widths.append(width)
        for r in range(self._rows):
            parts = [f"{self._data[r][c]:>{col_widths[c]}g}" for c in range(self._cols)]
            lines.append("[ " + "  ".join(parts) + " ]")
        return "\n".join(lines)

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Matrix):
            return NotImplemented
        if self.shape != other.shape:
            return False
        for r in range(self._rows):
            for c in range(self._cols):
                if self._data[r][c] != other._data[r][c]:
                    return False
        return True

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------

    def _check_bounds(self, row: int, col: int) -> None:
        if row < 0 or row >= self._rows:
            raise IndexError(
                f"Row {row} out of range for {self._rows}-row matrix"
            )
        if col < 0 or col >= self._cols:
            raise IndexError(
                f"Col {col} out of range for {self._cols}-col matrix"
            )
